package fr.ibrakash.helper.configuration.objects;

import fr.ibrakash.helper.item.AbstractItemReplacer;
import fr.ibrakash.helper.item.ItemUtil;
import fr.ibrakash.helper.item.replacer.ItemReplacer;
import fr.ibrakash.helper.text.TextReplacer;
import fr.ibrakash.helper.utils.ItemModelComponents;
import org.bukkit.Material;
import org.bukkit.inventory.ItemStack;
import org.bukkit.inventory.meta.ItemMeta;
import org.bukkit.inventory.meta.components.CustomModelDataComponent;

import java.util.ArrayList;
import java.util.Comparator;
import java.util.List;

public class AbstractConfigItem {

    private static final List<CustomItemParser> customParsers = new ArrayList<>();

    static {
        // Register default parsers
        registerParser(OraxenParser.getInstance());
        registerParser(NexoParser.getInstance());
        registerParser(ItemsAdderParser.getInstance());
    }

    private String customId = "";
    protected String material = Material.PAPER.name();
    protected int amount = 1;
    protected boolean unbreakable = false;
    protected String displayName = "";
    protected List<String> lore = new ArrayList<>();
    protected ItemModelComponents modelComponents = new ItemModelComponents();
    protected boolean glow = false;

    public ItemStack build(TextReplacer textReplacer) {
        return this.build(textReplacer, ItemReplacer.empty());
    }

    public ItemStack build(TextReplacer textReplacer, ItemReplacer itemReplacer) {
        return this.build(textReplacer, itemReplacer, null);
    }

    @SuppressWarnings("UnstableApiUsage")
    public <V> ItemStack build(TextReplacer textReplacer, AbstractItemReplacer<V> itemReplacer, V value) {
        ItemStack itemStack = null;

        // Try to parse custom item first if customId is provided
        if (customId != null && !customId.isEmpty()) {
            itemStack = parseCustomItem(customId);
        }

        // Fallback to normal material if custom item parsing failed
        if (itemStack == null) {
            itemStack = itemReplacer.createItemStack(value, this.material);
        }

        if (this.amount == 0) throw new IllegalArgumentException("ItemStack amount must be over 0");
        ItemMeta meta = itemStack.getItemMeta();
        meta.setUnbreakable(this.unbreakable);
        if (this.displayName != null && !displayName.isEmpty()) {
            meta.displayName(textReplacer.deserializeItemName(this.displayName));
        }

        if (!this.lore.isEmpty()) {
            meta.lore(textReplacer.deserializeItemLore(this.lore));
        }

        // TODO: Add a wrapper for legacy versions
        if (!modelComponents.isEmpty()) {
            CustomModelDataComponent component = meta.getCustomModelDataComponent();
            component.setFloats(this.modelComponents.getFloats());
            component.setStrings(this.modelComponents.getStrings());
            component.setFlags(this.modelComponents.getFlags());
            meta.setCustomModelDataComponent(component);
        }

        itemStack.setItemMeta(meta);

        if (this.glow) {
            ItemUtil.setGlow(itemStack, true);
        }
        return itemStack;
    }

    public String getMaterial() {
        return material;
    }

    public int getAmount() {
        return amount;
    }

    public boolean isUnbreakable() {
        return unbreakable;
    }

    public String getDisplayName() {
        return displayName;
    }

    public List<String> getLore() {
        return lore;
    }

    public ItemModelComponents getModelComponents() {
        return modelComponents;
    }

    public void setMaterial(String material) {
        this.material = material;
    }

    public void setAmount(int amount) {
        this.amount = amount;
    }

    public void setUnbreakable(boolean unbreakable) {
        this.unbreakable = unbreakable;
    }

    public void setDisplayName(String displayName) {
        this.displayName = displayName;
    }

    public void setLore(List<String> lore) {
        this.lore = lore;
    }

    public void setModelComponents(ItemModelComponents modelComponents) {
        this.modelComponents = modelComponents;
    }

    public String getCustomId() {
        return customId;
    }

    public void setCustomId(String customId) {
        this.customId = customId;
    }

    public boolean isGlow() {
        return glow;
    }

    public void setGlow(boolean glow) {
        this.glow = glow;
    }

    protected void copyValues(AbstractConfigItem from, AbstractConfigItem to) {
        to.material = from.material;
        to.amount = from.amount;
        to.unbreakable = from.unbreakable;
        to.displayName = from.displayName;
        to.lore = from.lore;
        to.modelComponents = from.modelComponents;
        to.customId = from.customId;
    }

    public static void registerParser(CustomItemParser parser) {
        if (parser != null) {
            customParsers.add(parser);
            // Sort by priority (highest first)
            customParsers.sort(Comparator.comparingInt(CustomItemParser::getPriority).reversed());
        }
    }

    private static ItemStack parseCustomItem(String customId) {
        if (customId == null || customId.isEmpty()) {
            return null;
        }

        // Try parsers in order of priority
        for (CustomItemParser parser : customParsers) {
            if (parser.supports(customId)) {
                ItemStack itemStack = parser.parseCustomItem(customId);
                if (itemStack != null) {
                    return itemStack;
                }
            }
        }
        return null;
    }
}

package fr.ibrakash.helper.configuration.objects;

import org.bukkit.inventory.ItemStack;

/**
 * Interface for parsing custom items from third-party plugins
 * Supports ItemsAdder, Oraxen, and Nexo
 */
public interface CustomItemParser {
    /**
     * Attempts to parse a custom item from the given ID
     * @param customId the custom item identifier
     * @return ItemStack if found, null otherwise
     */
    ItemStack parseCustomItem(String customId);

    /**
     * Checks if this parser supports the given custom item ID
     * @param customId the custom item identifier
     * @return true if this parser can handle it
     */
    boolean supports(String customId);

    /**
     * Gets the priority of this parser (higher = checked first)
     * @return priority level
     */
    default int getPriority() {
        return 0;
    }
}

package fr.ibrakash.helper.configuration.objects;

import org.bukkit.inventory.ItemStack;

/**
 * Custom item parser for ItemsAdder plugin
 */
public class ItemsAdderParser implements CustomItemParser {

    private static ItemsAdderParser instance;

    private ItemsAdderParser() {}

    public static ItemsAdderParser getInstance() {
        if (instance == null) {
            instance = new ItemsAdderParser();
        }
        return instance;
    }

    @Override
    public ItemStack parseCustomItem(String customId) {
        try {
            // ItemsAdder format: namespace:id
            Class<?> itemsAdderAPIClass = Class.forName("dev.lone.itemsadder.api.CustomStack");
            Object customStack = itemsAdderAPIClass
                    .getMethod("getInstance", String.class)
                    .invoke(null, customId);

            if (customStack != null) {
                ItemStack itemStack = (ItemStack) customStack
                        .getClass()
                        .getMethod("getItemStack")
                        .invoke(customStack);
                return itemStack != null ? itemStack.clone() : null;
            }
        } catch (Exception e) {
            // ItemsAdder not available or custom item not found
        }
        return null;
    }

    @Override
    public boolean supports(String customId) {
        // ItemsAdder custom IDs are typically in format "namespace:id"
        return customId != null && customId.contains(":") && isItemsAdderAvailable();
    }

    @Override
    public int getPriority() {
        return 10;
    }

    private static boolean isItemsAdderAvailable() {
        try {
            Class.forName("dev.lone.itemsadder.api.CustomStack");
            return true;
        } catch (ClassNotFoundException e) {
            return false;
        }
    }
}

package fr.ibrakash.helper.configuration.objects;

import org.bukkit.inventory.ItemStack;

/**
 * Custom item parser for Nexo plugin
 */
public class NexoParser implements CustomItemParser {

    private static NexoParser instance;

    private NexoParser() {}

    public static NexoParser getInstance() {
        if (instance == null) {
            instance = new NexoParser();
        }
        return instance;
    }

    @Override
    public ItemStack parseCustomItem(String customId) {
        try {
            // Nexo API
            Class<?> nexoItemsClass = Class.forName("com.nexomc.nexo.items.ItemRegistry");
            Object registry = nexoItemsClass
                    .getMethod("getInstance")
                    .invoke(null);

            Object nexoItem = registry
                    .getClass()
                    .getMethod("getItem", String.class)
                    .invoke(registry, customId);

            if (nexoItem != null) {
                ItemStack itemStack = (ItemStack) nexoItem
                        .getClass()
                        .getMethod("getItem")
                        .invoke(nexoItem);
                return itemStack != null ? itemStack.clone() : null;
            }
        } catch (Exception e) {
            // Nexo not available or custom item not found
        }
        return null;
    }

    @Override
    public boolean supports(String customId) {
        return customId != null && isNexoAvailable();
    }

    @Override
    public int getPriority() {
        return 15;
    }

    private static boolean isNexoAvailable() {
        try {
            Class.forName("com.nexomc.nexo.items.ItemRegistry");
            return true;
        } catch (ClassNotFoundException e) {
            return false;
        }
    }
}

package fr.ibrakash.helper.configuration.objects;

import org.bukkit.inventory.ItemStack;

/**
 * Custom item parser for Oraxen plugin
 */
public class OraxenParser implements CustomItemParser {

    private static OraxenParser instance;

    private OraxenParser() {}

    public static OraxenParser getInstance() {
        if (instance == null) {
            instance = new OraxenParser();
        }
        return instance;
    }

    @Override
    public ItemStack parseCustomItem(String customId) {
        try {
            // Oraxen API
            Class<?> oraxenItemsAPIClass = Class.forName("io.th0rgal.oraxen.items.OraxenItems");
            Object oraxenItem = oraxenItemsAPIClass
                    .getMethod("getItemById", String.class)
                    .invoke(null, customId);

            if (oraxenItem != null) {
                ItemStack itemStack = (ItemStack) oraxenItem
                        .getClass()
                        .getMethod("build")
                        .invoke(oraxenItem);
                return itemStack != null ? itemStack.clone() : null;
            }
        } catch (Exception e) {
            // Oraxen not available or custom item not found
        }
        return null;
    }

    @Override
    public boolean supports(String customId) {
        return customId != null && !customId.contains(":") && isOraxenAvailable();
    }

    @Override
    public int getPriority() {
        return 20;
    }

    private static boolean isOraxenAvailable() {
        try {
            Class.forName("io.th0rgal.oraxen.items.OraxenItems");
            return true;
        } catch (ClassNotFoundException e) {
            return false;
        }
    }
}
